class ASTNode:
    def __init__(self, node_type, **kwargs):
        self.type = node_type
        if node_type == 'number':
            self.value = kwargs.get('value')
        elif node_type == 'binop':
            self.op = kwargs.get('op')
            self.left = kwargs.get('left')
            self.right = kwargs.get('right')
        elif node_type == 'unary':
            self.op = kwargs.get('op')
            self.operand = kwargs.get('operand')

    def __repr__(self):
        if self.type == 'number':
            return f"Number({self.value})"
        elif self.type == 'binop':
            return f"BinOp({self.op}, {self.left}, {self.right})"
        elif self.type == 'unary':
            return f"UnaryOp({self.op}, {self.operand})"


def parse(expression: str) -> ASTNode:
    tokens = tokenize(expression)
    if not tokens:
        raise ValueError("Empty expression")

    return parse_expression(tokens)


def tokenize(expression: str) -> list:
    tokens = []
    i = 0
    n = len(expression)

    while i < n:
        c = expression[i]

        if c.isspace():
            i += 1
            continue

        if c in '()+-*/':
            tokens.append(c)
            i += 1
        elif c.isdigit() or c == '.':
            num_str = []
            has_dot = False

            while i < n and (expression[i].isdigit() or expression[i] == '.'):
                if expression[i] == '.':
                    if has_dot:
                        raise ValueError("Invalid number format")
                    has_dot = True
                num_str.append(expression[i])
                i += 1

            tokens.append(''.join(num_str))
        else:
            raise ValueError(f"Invalid token: '{c}'")

    return tokens


def parse_expression(tokens: list) -> ASTNode:
    return parse_additive(tokens)


def parse_additive(tokens: list) -> ASTNode:
    node = parse_multiplicative(tokens)

    while tokens and tokens[0] in ('+', '-'):
        op = tokens.pop(0)
        right = parse_multiplicative(tokens)
        node = ASTNode('binop', op=op, left=node, right=right)

    return node


def parse_multiplicative(tokens: list) -> ASTNode:
    node = parse_unary(tokens)

    while tokens and tokens[0] in ('*', '/'):
        op = tokens.pop(0)
        right = parse_unary(tokens)
        node = ASTNode('binop', op=op, left=node, right=right)

    return node


def parse_unary(tokens: list) -> ASTNode:
    unary_count = 0
    while tokens and tokens[0] == '-':
        tokens.pop(0)
        unary_count += 1

    operand = parse_primary(tokens)

    if unary_count > 0:
        # If odd number of minuses, it's negative; if even, it's positive
        op = '-' if unary_count % 2 == 1 else '+'
        if op == '-':
            return ASTNode('unary', op='-', operand=operand)
        else:
            return operand

    return operand


def parse_primary(tokens: list) -> ASTNode:
    if not tokens:
        raise ValueError("Unexpected end of expression")

    token = tokens.pop(0)

    if token == '(':
        node = parse_expression(tokens)
        if not tokens or tokens[0] != ')':
            raise ValueError("Unmatched parentheses")
        tokens.pop(0)
        return node
    elif token.replace('.', '', 1).isdigit():
        try:
            value = float(token)
            return ASTNode('number', value=value)
        except ValueError:
            raise ValueError("Invalid number format")
    else:
        raise ValueError(f"Unexpected token: '{token}'")


def evaluate(node: ASTNode) -> float:
    if node.type == 'number':
        return node.value
    elif node.type == 'binop':
        left_val = evaluate(node.left)
        right_val = evaluate(node.right)

        if node.op == '+':
            return left_val + right_val
        elif node.op == '-':
            return left_val - right_val
        elif node.op == '*':
            return left_val * right_val
        elif node.op == '/':
            if right_val == 0:
                raise ZeroDivisionError("Division by zero")
            return left_val / right_val
    elif node.type == 'unary':
        operand_val = evaluate(node.operand)
        if node.op == '-':
            return -operand_val

    raise ValueError(f"Unknown node type: {node.type}")

import unittest
from expr_parser import parse, evaluate, ASTNode


class TestExprParser(unittest.TestCase):
    def test_simple_number(self):
        node = parse("42")
        self.assertEqual(evaluate(node), 42.0)

    def test_negative_number(self):
        node = parse("-42")
        self.assertEqual(evaluate(node), -42.0)

    def test_basic_addition(self):
        node = parse("2 + 3")
        self.assertEqual(evaluate(node), 5.0)

    def test_basic_subtraction(self):
        node = parse("5 - 3")
        self.assertEqual(evaluate(node), 2.0)

    def test_basic_multiplication(self):
        node = parse("2 * 3")
        self.assertEqual(evaluate(node), 6.0)

    def test_basic_division(self):
        node = parse("6 / 3")
        self.assertEqual(evaluate(node), 2.0)

    def test_operator_precedence(self):
        node = parse("2 + 3 * 4")
        self.assertEqual(evaluate(node), 14.0)

    def test_division_precedence(self):
        node = parse("12 / 3 * 2")
        self.assertEqual(evaluate(node), 8.0)

    def test_parentheses(self):
        node = parse("(2 + 3) * 4")
        self.assertEqual(evaluate(node), 20.0)

    def test_unary_with_parentheses(self):
        node = parse("-(2 + 3)")
        self.assertEqual(evaluate(node), -5.0)

    def test_complex_expression(self):
        node = parse("2 + 3 * (4 - 1) / 3")
        self.assertEqual(evaluate(node), 5.0)

    def test_decimal_numbers(self):
        node = parse("1.5 + 2.5")
        self.assertEqual(evaluate(node), 4.0)

    def test_negative_decimal(self):
        node = parse("-1.5")
        self.assertEqual(evaluate(node), -1.5)

    def test_division_by_zero(self):
        node = parse("1 / 0")
        with self.assertRaises(ZeroDivisionError):
            evaluate(node)

    def test_empty_expression(self):
        with self.assertRaises(ValueError) as cm:
            parse("")
        self.assertEqual(str(cm.exception), "Empty expression")

    def test_invalid_token(self):
        with self.assertRaises(ValueError) as cm:
            parse("2 + a")
        self.assertEqual(str(cm.exception), "Invalid token: 'a'")

    def test_unmatched_parentheses(self):
        with self.assertRaises(ValueError) as cm:
            parse("(2 + 3")
        self.assertEqual(str(cm.exception), "Unmatched parentheses")

    def test_invalid_number_format(self):
        with self.assertRaises(ValueError) as cm:
            parse("2..5")
        self.assertEqual(str(cm.exception), "Invalid number format")

    def test_nested_parentheses(self):
        node = parse("2 + (3 * (4 + 1))")
        self.assertEqual(evaluate(node), 17.0)

    def test_multiple_unary(self):
        node = parse("--5")
        self.assertEqual(evaluate(node), 5.0)

    def test_unary_precedence(self):
        node = parse("2 * -3")
        self.assertEqual(evaluate(node), -6.0)


if __name__ == '__main__':
    unittest.main()
